128â†’// MarshalJSON implements json.Marshaler.
129â†’//
130â†’// JSON marshaling is only needed for the HTTP API. Since HPoint is such a
131â†’// frequently marshaled type, it gets an optimized treatment directly in
132â†’// web/api/v1/api.go. Therefore, this method is unused within Prometheus. It is
133â†’// still provided here as convenience for debugging and for other users of this
134â†’// code. Also note that the different marshaling implementations might lead to
135â†’// slightly different results in terms of formatting and rounding of the
136â†’// timestamp.
137â†’func (p HPoint) MarshalJSON() ([]byte, error) {
138â†’	h := struct {
139â†’		Count   string  `json:"count"`
140â†’		Sum     string  `json:"sum"`
141â†’		Buckets [][]any `json:"buckets,omitempty"`
142â†’	}{
143â†’		Count: strconv.FormatFloat(p.H.Count, 'f', -1, 64),
144â†’		Sum:   strconv.FormatFloat(p.H.Sum, 'f', -1, 64),
145â†’	}
146â†’	it := p.H.AllBucketIterator()
147â†’	for it.Next() {
148â†’		bucket := it.At()
149â†’		if bucket.Count == 0 {
150â†’			continue // No need to expose empty buckets in JSON.
151â†’		}
152â†’		boundaries := 2 // Exclusive on both sides AKA open interval.
153â†’		if bucket.LowerInclusive {
154â†’			if bucket.UpperInclusive {
155â†’				boundaries = 3 // Inclusive on both sides AKA closed interval.
156â†’			} else {
157â†’				boundaries = 1 // Inclusive only on lower end AKA right open.
158â†’			}
159â†’		} else {
160â†’			if bucket.UpperInclusive {
161â†’				boundaries = 0 // Inclusive only on upper end AKA left open.
162â†’			}
163â†’		}
164â†’		bucketToMarshal := []any{
165â†’			boundaries,
166â†’			strconv.FormatFloat(bucket.Lower, 'f', -1, 64),
167â†’			strconv.FormatFloat(bucket.Upper, 'f', -1, 64),
168â†’			strconv.FormatFloat(bucket.Count, 'f', -1, 64),
169â†’		}
170â†’		h.Buckets = append(h.Buckets, bucketToMarshal)
171â†’	}
172â†’	return json.Marshal([...]any{float64(p.T) / 1000, h})
173â†’}
